var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......그래서 편입 첫날부터 학교에서 제일 비싼 장비를 때려 부쉈다는 말이로군.","JPN":"……というわけで、編入初日から学校で一番高い装置をぶち壊したってことか。","ENG":"So... that's why you broke the Academy's most expensive equipment on your first day here.","TWN":"所以說……你在入學第一天就砸掉了學校裡最貴的設備。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아하하...... 미안해. 선생님.","JPN":"ア、アハハ……ごめんね、先生。","ENG":"Ah... Hah hah... Sorry, Prof.","TWN":"啊，哈哈哈……真對不起，老師。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 혹시...... 이제 어떻게 되는 거야?","JPN":"ところで……これからどうなるの？","ENG":"By the way... What's going to happen to me now?","TWN":"那現在……會怎麼樣？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서, 설마 기계 값을 물어내라고 하진 않겠지?","JPN":"も、もしかして私が弁償することにはならないよね？","ENG":"Y-you're not going to make me pay for that machine, are you?","TWN":"不會讓我賠機器吧？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네에겐 다행스럽게도 배상 문제는 걱정하지 않아도 좋네.","JPN":"幸い、その辺は君が心配しなくてもいい。","ENG":"Luckily for you, you won't have to worry about compensating the Academy.","TWN":"你很幸運，不用擔心賠償的問題。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"학생들에게는 알리지 않았지만, 그건 사실 베타 테스트 용으로 설치된 장비거든.","JPN":"生徒には知られていないが、実はあの機械はベータテスト用の設備だ。","ENG":"Unbeknownst to the students, that equipment was actually set up for a beta test.","TWN":"雖然沒有跟學生們說，但其實安裝那台機器是為了進行最後測試。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"관리국의 엔지니어들이 시뮬레이터가 폭주를 일으켰단 소식에 아주 기뻐하더군.","JPN":"管理局のエンジニアたちはシミュレーターが暴走したという報告を受けて、とても喜んでいたらしい。","ENG":"The engineers over at the Administration were thrilled to hear about the system going overboard.","TWN":"管理局的工程師聽說模擬器暴走之後非常高興。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자기들이 예상 못한 버그를 찾아냈다고 말이야.","JPN":"予想できなかった不具合が見つかってよかったそうだ。","ENG":"Apparently you guys found a bug they didn't anticipate.","TWN":"說是我們發現了他們沒有預想到的缺陷。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 친구들도 염치가 있다면 학생에게 배상하라는 말은 못하겠지.","JPN":"あの人たちに良心があるのであれば、生徒に弁償などと言わないだろう。","ENG":"If anything, they're not so shameless to make you pay for helping them find the bug.","TWN":"他們還有良心的話，不會好意思讓學生賠償的。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다, 다행이다......","JPN":"よ、よかった……","ENG":"Th-thank goodness...","TWN":"真、真是太好了……"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"징계 위원회도 따로 열리진 않을 거다.","JPN":"懲戒委員会も開かれないだろう。","ENG":"There will not be a disciplinary hearing either.","TWN":"也不會召開懲戒委員會。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"원인이 뭐가 됐건 학생들의 안전을 위한 비상 행동이었으니까.","JPN":"原因が何であれ、生徒の安全のための行動だったからな。","ENG":"Regardless of the cause, your actions ensured the safety of the students.","TWN":"不管原因如何，你是為了學生們的安全才採取的緊急措施。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 다음에 또 이런 일이 벌어지면, 그때는 가급적 온건한 방식을 사용해 주면 좋겠군.","JPN":"しかし今度また同じようなことになったら、その時はできれば穏やかなやり方で解決してくれると助かる。","ENG":"But I hope you'll take a more subtle approach should anything like this happen again.","TWN":"但如果下次再發生這種事情，我希望你能用溫和一些的方法。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예를 들어 경찰을 부른다거나 말이지.","JPN":"例えば、警察を呼ぶとかな。","ENG":"Like calling the cops, for instance.","TWN":"比如叫警察。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"알겠나?","JPN":"わかったか？","ENG":"Understood?","TWN":"知道了嗎？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마. 앞으로 시뮬레이터는 근처에도 안 갈 테니까.","JPN":"心配しないで。これからシミュレーターを使うつもりもないから。","ENG":"Don't worry. I'm not going anywhere near that simulator from now on.","TWN":"別擔心。我以後不會靠近模擬器的。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말이 잘 통해서 좋군.","JPN":"物わかりの良い性格で助かる。","ENG":"I'm glad I could get through to you.","TWN":"那就好。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"약간의 불미스러운 일이 있었지만, 결과적으로 자네 실력만큼은 확실히 검증되었다고 해도 되겠지.","JPN":"多少のトラブルはあったが、結果的に君の実力は間違いないということが実証できたとも言える。","ENG":"Despite the minor hiccup, I guess this definitely proved what you're capable of.","TWN":"雖然發生了一些事情，但整體來說已經充分證明了你的實力。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"편입 직후라 어떻게 할지 고민했는데, 쓸데없는 짓이었어.","JPN":"編入直後だからどうしようか悩んだが、無駄な悩みだったな。","ENG":"We were trying to figure out how to test you right after your transfer, but I guess there was no point.","TWN":"我本來還擔心你剛來會無法適應，看來是我多想了。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};